from flask import Flask, request
from prometheus_client import start_http_server, Summary, Counter
from collections import defaultdict

app = Flask(__name__)
USER_PATH_COUNTERS = defaultdict(lambda: Counter('http_requests_total', 'Total HTTP Requests', ['user_id', 'session_id', 'path']))

@app.route('/<path:subpath>', methods=['GET', 'POST', 'PUT', 'DELETE'])
def track_requests(subpath):
    user_id = request.args.get('user_id', 'unknown')
    session_id = request.args.get('session_id', 'unknown')
    
    path = request.full_path
    USER_PATH_COUNTERS[(user_id, path)].labels(user_id=user_id, session_id=session_id, path=path).inc()

    return f"Request tracked for User: {user_id}, Session: {session_id}, Path: {path}", 200

